#!/usr/bin/env python3
# -*- coding: utf-8 -*-
"""
Correctif "Boire un verre" : generalisation du systeme d'invitation
(reutilise et generalise ce qui a ete construit pour le Diner d'affaires).
- plateau-pnj.js : remplace les fonctions specifiques au diner par des
  fonctions generiques (CONFIG_INVITATIONS_SOCIALES, ouvrirModalInvitationSociale,
  envoyerInvitationSociale, verifierReponseInvitationSociale,
  verifierInvitationsSocialesRecues, repondreInvitationSociale)
- supabase.js : sbCreerInvitationDiner accepte maintenant un type
- plateau-router.js : routes generiques pour diner_affaires et boire_verre
- data.js : "Boire un verre" au bar devient une invitation (50 FR, +5 Sante,
  +2 INF, +2 ENT pour chacun si accepte)
- plateau-actions-illegales-rumeurs.js : formulations de rumeur pour boire_verre
"""
import sys

def apply_patch(path, old, new, label):
    with open(path, 'r', encoding='utf-8') as f:
        content = f.read()
    count = content.count(old)
    if count == 0:
        print(f"[ECHEC] {label} : ancre introuvable dans {path}")
        return False
    if count > 1:
        print(f"[ECHEC] {label} : ancre trouvee {count} fois dans {path} (doit etre unique)")
        return False
    content = content.replace(old, new, 1)
    with open(path, 'w', encoding='utf-8') as f:
        f.write(content)
    print(f"[OK] {label}")
    return True

ok = True

